class TTLCache:
    """LRU cache with per-entry TTL (time-to-live).
    When the cache is full, the least recently used entry is evicted.
    Expired entries are treated as non-existent.
    """
    def __init__(self, max_size):
        self.max_size = int(max(0, max_size))
        self._cache = OrderedDict()  # key -> (value, expiry_time)

    def _now(self):
        return time.monotonic()

    def _purge_expired(self, now=None):
        """Remove all expired entries. Returns number of purged entries."""
        if now is None:
            now = self._now()
        expired_keys = [k for k, (_, expiry) in self._cache.items() if now >= expiry]
        for k in expired_keys:
            del self._cache[k]
        return len(expired_keys)

    def get(self, key):
        """Get a value. Returns None if key doesn't exist or is expired."""
        if key not in self._cache:
            return None
        value, expiry = self._cache[key]
        if self._now() >= expiry:
            # Entry has expired
            del self._cache[key]
            return None
        # Move to end (most recently used)
        self._cache.move_to_end(key)
        return value

    def put(self, key, value, ttl_seconds=60):
        """Put a value with a TTL. Evicts LRU entry if cache is full.
        Expired entries are purged prior to capacity checks.
        """
        now = self._now()
        # Purge expired entries first so they don't count toward capacity
        self._purge_expired(now)

        # If capacity is zero, do not store anything
        if self.max_size <= 0:
            # Ensure key is not present
            self._cache.pop(key, None)
            return

        # Non-positive TTL means the entry is immediately expired; treat as no-op (remove if exists)
        try:
            ttl = float(ttl_seconds)
        except (TypeError, ValueError):
            # Invalid TTL; ignore insert
            return
        if ttl <= 0:
            self._cache.pop(key, None)
            return

        expiry = now + ttl

        if key in self._cache:
            # Update existing (whether previously expired or not—expired ones would have been purged)
            self._cache[key] = (value, expiry)
            self._cache.move_to_end(key)
            return

        # Ensure capacity by evicting LRU non-expired entries if needed
        if len(self._cache) >= self.max_size:
            self._cache.popitem(last=False)

        self._cache[key] = (value, expiry)

    def size(self):
        """Return number of non-expired entries."""
        self._purge_expired()
        return len(self._cache)

    def clear(self):
        """Clear all entries."""
        self._cache.clear()

